class Solution {
public:
    int countKReducibleNumbers(string s, int k) {
        int n = s.size();
        long long mod = 1e9 + 7;
        long long dp[n + 1][k + 1];
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= k; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j <= k; j++) {
                if (j > 0) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % mod;
                }
                int ones = 0;
                int x = i - 1;
                while (x >= 0 && s[x] == '1') {
                    ones++;
                    x--;
                }
                dp[i][j] = (dp[i][j] + dp[x + 1][j]) % mod;
            }
        }
        long long ans = 0;
        for (int i = 0; i <= k; i++) {
            ans = (ans + dp[n][i]) % mod;
        }
        return ans;
    }
};
```

